parameters.jsonSchemaExample:
{
    "status": {
      "type": "string",
      "enum": ["Booked", "Unsure", "Rejected"],
      "description": "The current status of the call."
    },
    "call_summary": {
      "type": "string",
      "description": "A brief summary of the conversation."
    },
    "call_transcript": {
      "type": "string",
      "description": "The full text transcript of the call."
    },
    "booked_date_time": {
      "type": ["string", "null"],
      "description": "This will be booking date and time if call is booked. Date time format will be DD/MM/YY-HH:MM"
    },
    "follow_up": {
      "type": ["string", "null"],
      "description": "This will be follow up date if user doesn't pick up call or tells to reschedule the call"
  }
}
